// src/generators/fade-up.ts
function generateFadeUp(props) {
  const duration = props.duration ?? 0.6;
  const delay = props.delay ?? 0;
  const distance = props.distance ?? 32;
  const ease = props.ease ?? "easeOut";
  const once = props.once ?? true;
  return `// ForgeFadeUp.tsx \u2014 generated by forge-motion CLI
// Edit this file freely \u2014 you own it.
// Re-generate with: npx @forgelabs-studio/motion update fade-up

'use client'

import type { ReactNode } from 'react'
import { useRef } from 'react'
import { motion, useInView } from 'framer-motion'

interface ForgeFadeUpProps {
  children: ReactNode
  duration?: number
  delay?: number
  distance?: number
  ease?: string
  once?: boolean
}

export function ForgeFadeUp({
  children,
  duration = ${duration},
  delay = ${delay},
  distance = ${distance},
  ease = '${ease}',
  once = ${once},
}: ForgeFadeUpProps) {
  const ref = useRef<HTMLDivElement>(null)
  const inView = useInView(ref, { once, amount: 0.3 })
  const prefersReduced =
    typeof window !== 'undefined'
      ? window.matchMedia('(prefers-reduced-motion: reduce)').matches
      : false

  return (
    <motion.div
      ref={ref}
      initial={prefersReduced ? false : { opacity: 0, y: distance }}
      animate={prefersReduced ? { opacity: 1, y: 0 } : inView ? { opacity: 1, y: 0 } : { opacity: 0, y: distance }}
      transition={prefersReduced ? { duration: 0 } : { duration, delay, ease }}
    >
      {children}
    </motion.div>
  )
}
`;
}

