// src/generators/count-up.ts
function generateCountUp(props) {
  const from = props.from ?? 0;
  const to = props.to ?? 100;
  const duration = props.duration ?? 1.5;
  const once = props.once ?? true;
  return `// ForgeCountUp.tsx \u2014 generated by forge-motion CLI
// Edit this file freely \u2014 you own it.
// Re-generate with: npx @forgelabs-studio/motion update count-up

'use client'

import { useRef, useEffect } from 'react'
import { useInView, useMotionValue, useTransform, animate, motion } from 'framer-motion'

interface ForgeCountUpProps {
  from?: number
  to?: number
  duration?: number
  once?: boolean
}

export function ForgeCountUp({
  from = ${from},
  to = ${to},
  duration = ${duration},
  once = ${once},
}: ForgeCountUpProps) {
  const ref = useRef<HTMLSpanElement>(null)
  const inView = useInView(ref, { once, amount: 0.5 })
  const count = useMotionValue(from)
  const rounded = useTransform(count, (v) => Math.round(v))
  const prefersReduced =
    typeof window !== 'undefined'
      ? window.matchMedia('(prefers-reduced-motion: reduce)').matches
      : false

  useEffect(() => {
    if (!inView) return
    count.set(from)
    const controls = animate(count, to, {
      duration: prefersReduced ? 0 : duration,
      ease: 'easeOut',
    })
    return () => controls.stop()
  }, [inView, from, to, duration, prefersReduced, count])

  return <motion.span ref={ref}>{rounded}</motion.span>
}
`;
}

// src/generators/typewriter.ts
function generateTypewriter(props) {
  const text = props.text ?? "Interfaces built to a standard you can feel.";
  const speed = props.speed ?? 40;
  const once = props.once ?? true;
  return `// ForgeTypewriter.tsx \u2014 generated by forge-motion CLI
// Edit this file freely \u2014 you own it.
// Re-generate with: npx @forgelabs-studio/motion update typewriter

'use client'

import { useRef, useState, useEffect } from 'react'
import { useInView } from 'framer-motion'

interface ForgeTypewriterProps {
  text?: string
  speed?: number
  once?: boolean
}

export function ForgeTypewriter({
  text = ${JSON.stringify(text)},
  speed = ${speed},
  once = ${once},
}: ForgeTypewriterProps) {
  const ref = useRef<HTMLSpanElement>(null)
  const inView = useInView(ref, { once, amount: 0.3 })
  const [displayed, setDisplayed] = useState('')
  const prefersReduced =
    typeof window !== 'undefined'
      ? window.matchMedia('(prefers-reduced-motion: reduce)').matches
      : false

  useEffect(() => {
    if (!inView) return
    if (prefersReduced) {
      setDisplayed(text)
      return
    }
    setDisplayed('')
    let i = 0
    const interval = setInterval(() => {
      i++
      setDisplayed(text.slice(0, i))
      if (i >= text.length) clearInterval(interval)
    }, speed)
    return () => clearInterval(interval)
  }, [inView, text, speed, prefersReduced])

  return <span ref={ref}>{displayed}</span>
}
`;
}

// src/generate.ts
var GENERATORS = {
  "fade-up": generateFadeUp,
  "fade-down": generateFadeDown,
  "fade-in": generateFadeIn,
  "slide-in-left": generateSlideInLeft,
  "slide-in-right": generateSlideInRight,
  "scale-in": generateScaleIn,
  "bounce-in": generateBounceIn,
  "stagger": generateStagger,
  "parallax": generateParallax,
  "reveal": generateReveal,
  "float": generateFloat,
  "pulse": generatePulse,
  "count-up": generateCountUp,
  "typewriter": generateTypewriter
};
async function generatePreset(presetId, displayName, props, config) {
  const generator = GENERATORS[presetId];
  if (!generator) throw new Error(`No generator found for preset: ${presetId}`);
  const tsx = generator(props);
  const outputDir = path2.join(process.cwd(), config.output);
  await fs2.ensureDir(outputDir);
  await fs2.writeFile(path2.join(outputDir, `${displayName}.tsx`), tsx, "utf8");
}

// src/manifest.ts
import fs3 from "fs-extra";
import path3 from "path";
var MANIFEST_FILE = ".forge.json";
var MOTION_KEY2 = "motion";
async function readManifest() {
  const manifestPath = path3.join(process.cwd(), MANIFEST_FILE);
  if (!await fs3.pathExists(manifestPath)) return {};
  const full = await fs3.readJson(manifestPath);
  return full[MOTION_KEY2] ?? {};
}
async function writeManifest(manifest) {
  const manifestPath = path3.join(process.cwd(), MANIFEST_FILE);
  const full = await fs3.pathExists(manifestPath) ? await fs3.readJson(manifestPath) : {};
  full[MOTION_KEY2] = manifest;
  await fs3.writeJson(manifestPath, full, { spaces: 2 });
}
async function setPresetVersion(presetId, version) {
  const manifest = await readManifest();
  manifest[presetId] = version;
  await writeManifest(manifest);
}
async function removePresetVersion(presetId) {
  const manifest = await readManifest();
  delete manifest[presetId];
  await writeManifest(manifest);
}

// src/flags.ts
var FLAG_TO_PROP = {
  "--duration": "duration",
  "--delay": "delay",
  "--distance": "distance",
  "--ease": "ease",
  "--once": "once",
  "--scale": "scale",
  "--stiffness": "stiffness",
  "--damping": "damping",
  "--stagger-delay": "staggerDelay",
  "--speed": "speed",
  "--from": "from",
  "--to": "to",
  "--text": "text"
};
var NUMBER_PROPS = /* @__PURE__ */ new Set([
  "duration",
  "delay",
  "distance",
  "scale",
  "stiffness",
  "damping",
  "staggerDelay",
  "speed",
  "from",
  "to"
]);
var EASE_VALUES = /* @__PURE__ */ new Set(["linear", "easeIn", "easeOut", "easeInOut"]);
function coerceValue(prop, value) {
  if (typeof value === "boolean") return value;
  if (prop === "once") return value !== "false";
  if (prop === "ease" && !EASE_VALUES.has(value)) {
    throw new Error(`Invalid easing value: ${value}`);
  }
  if (!NUMBER_PROPS.has(prop)) return value;
  const parsed = Number(value);
  if (!Number.isFinite(parsed)) {
    throw new Error(`Invalid numeric value for ${prop}: ${value}`);
  }
  return parsed;
}
function parseMotionFlags(rawFlags) {
  const props = {};
  for (let i = 0; i < rawFlags.length; i += 1) {
    const current = rawFlags[i];
    if (!current.startsWith("--")) continue;
    const equalsIndex = current.indexOf("=");
    const flag = equalsIndex === -1 ? current : current.slice(0, equalsIndex);
    const inlineValue = equalsIndex === -1 ? void 0 : current.slice(equalsIndex + 1);
    const prop = FLAG_TO_PROP[flag];
    if (!prop) continue;
    const next = rawFlags[i + 1];
    let value;
    if (inlineValue !== void 0) {
      value = inlineValue;
    } else if (next && !next.startsWith("--")) {
      value = next;
      i += 1;
    } else {
      value = true;
    }
    props[prop] = coerceValue(prop, value);
  }
  return props;
}

// src/version.ts
var PACKAGE_VERSION = "0.1.0";

// src/commands/add.ts
async function runAdd(presetId, rawFlags) {
  console.log(pc.bold(`
  forge-motion add ${presetId}
`));
  const meta = REGISTRY_BY_ID[presetId];
  if (!meta) {
    console.log(pc.red(`  Unknown preset: "${presetId}"`));
    console.log(pc.dim("  Run npx @forgelabs-studio/motion list to see available presets.\n"));
    process.exit(1);
  }
  try {
    let config = await readConfig();
    if (!config) {
      config = createDefaultConfig();
      console.log(pc.dim("  No motion config found in forge.config.json \u2014 creating one.\n"));
    }
    const props = parseMotionFlags(rawFlags);
    await generatePreset(presetId, meta.displayName, props, config);
    config.presets[presetId] = props;
    await writeConfig(config);
    await setPresetVersion(presetId, PACKAGE_VERSION);
    console.log(pc.green("  \u2713") + ` ${meta.displayName}.tsx`);
    console.log(pc.dim(`
  Import with:`));
    console.log(pc.cyan(`  import { ${meta.displayName} } from '@/components/motion/${meta.displayName}'
`));
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(pc.red(`
  \u2716 Failed to add ${presetId}: ${message}
`));
    process.exit(1);
  }
}

// src/commands/list.ts
import pc2 from "picocolors";
async function runList() {
  console.log(pc2.bold("\n  FORGE.motion presets\n"));
  const config = await readConfig();
  const installed = new Set(Object.keys(config?.presets ?? {}));
  for (const preset of REGISTRY) {
    const tick = installed.has(preset.id) ? pc2.green("\u2713") : pc2.dim("\u25CB");
    console.log(`  ${tick} ${pc2.white(preset.displayName.padEnd(24))} ${pc2.dim(preset.description)}`);
  }
  console.log();
}

// src/commands/update.ts
import pc3 from "picocolors";
async function runUpdate(presetId) {
  console.log(pc3.bold(`
  forge-motion update ${presetId}
`));
  try {
    const config = await readConfig();
    if (!config) {
      console.log(pc3.red("  No forge.config.json found.\n"));
      process.exit(1);
    }
    const meta = REGISTRY_BY_ID[presetId];
    if (!meta) {
      console.log(pc3.red(`  Unknown preset: "${presetId}"
`));
      process.exit(1);
    }
    const props = config.presets[presetId] ?? {};
    await generatePreset(presetId, meta.displayName, props, config);
    config.presets[presetId] = props;
    await writeConfig(config);
    console.log(pc3.green("  \u2713") + ` ${meta.displayName}.tsx regenerated
`);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(pc3.red(`
  \u2716 Failed to update ${presetId}: ${message}
`));
    process.exit(1);
  }
}

// src/commands/remove.ts
import fs4 from "fs-extra";
import path4 from "path";
import pc4 from "picocolors";
async function runRemove(presetId) {
  console.log(pc4.bold(`
  forge-motion remove ${presetId}
`));
  try {
    const config = await readConfig();
    if (!config) {
      console.log(pc4.red("  No forge.config.json found.\n"));
      process.exit(1);
    }
    const meta = REGISTRY_BY_ID[presetId];
    if (!meta) {
      console.log(pc4.red(`  Unknown preset: "${presetId}"
`));
      process.exit(1);
    }
    const outputDir = path4.join(process.cwd(), config.output);
    const tsxPath = path4.join(outputDir, `${meta.displayName}.tsx`);
    if (await fs4.pathExists(tsxPath)) {
      await fs4.remove(tsxPath);
      console.log(pc4.red("  \u2715") + ` ${meta.displayName}.tsx`);
    }
    delete config.presets[presetId];
    await writeConfig(config);
    await removePresetVersion(presetId);
    console.log(pc4.dim("\n  Removed from forge.config.json.\n"));
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(pc4.red(`
  \u2716 Failed to remove ${presetId}: ${message}
`));
    process.exit(1);
  }
}

// src/commands/check.ts
import pc5 from "picocolors";
import semver from "semver";
var PACKAGE_NAME = "@forgelabs-studio/motion";
async function fetchLatestVersion() {
  const res = await fetch(`https://registry.npmjs.org/${PACKAGE_NAME}/latest`);
  if (!res.ok) throw new Error(`npm registry returned ${res.status}`);
  const data = await res.json();
  return data.version;
}
async function runCheck() {
  console.log(pc5.bold("\n  forge-motion check\n"));
  try {
    const manifest = await readManifest();
    const installed = Object.entries(manifest);
    if (installed.length === 0) {
      console.log(pc5.dim("  No presets installed. Run npx @forgelabs-studio/motion add <preset> to get started.\n"));
      return;
    }
    console.log(pc5.dim("  Checking latest version on npm\u2026\n"));
    const latest = await fetchLatestVersion();
    let allUpToDate = true;
    for (const [presetId, installedVersion] of installed) {
      const isOutdated = semver.lt(installedVersion, latest);
      if (isOutdated) {
        allUpToDate = false;
        console.log(
          `  ${pc5.yellow("!")} ${pc5.white(presetId.padEnd(20))} ${pc5.dim(installedVersion)} \u2192 ${pc5.cyan(latest)}`
        );
      } else {
        console.log(
          `  ${pc5.green("\u2713")} ${pc5.white(presetId.padEnd(20))} ${pc5.dim(installedVersion)}`
        );
      }
    }
    if (!allUpToDate) {
      console.log(pc5.dim("\n  Update with: npx @forgelabs-studio/motion update <preset>\n"));
    } else {
      console.log(pc5.dim("\n  All presets are up to date.\n"));
    }
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(pc5.red(`
  \u2716 Check failed: ${message}
`));
    process.exit(1);
  }
}

// src/index.ts
var program = new Command();
program.name("forge-motion").description("FORGE.motion \u2014 scroll-triggered and viewport-aware animation presets for React").version(PACKAGE_VERSION);
program.command("add <preset>").description("Add a motion preset").allowUnknownOption(true).action((preset, _opts, cmd) => {
  const rawFlags = cmd.args.slice(1);
  runAdd(preset, rawFlags);
});
program.command("list").description("List all available and installed presets").action(() => runList());
program.command("update <preset>").description("Regenerate a preset using its saved configuration").action((preset) => runUpdate(preset));
program.command("remove <preset>").description("Remove a preset and its files").action((preset) => runRemove(preset));
program.command("check").description("Check installed presets against the latest published version").action(() => runCheck());
program.parse();
